<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        /* --- Global Reset & Theme --- */
        :root {
            --bg-color: #2b3e46; /* Dark Ubuntu background */
            --taskbar-bg: rgba(35, 58, 70, 0.9);
            --window-bg: #3a4d5c;
            --text-color: #ececec;
            --accent-color: #42a5f5; /* Ubuntu blue */
            --border-color: #1e2b33;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body, html {
            height: 100%;
            overflow: hidden;
            background-color: var(--bg-color);
            color: var(--text-color);
        }

        /* --- Desktop Structure --- */
        #desktop {
            position: relative;
            width: 100%;
            height: calc(100% - 40px); /* Account for taskbar height */
            padding-bottom: 40px; /* Ensure content doesn't hide under the taskbar */
        }

        /* --- Taskbar/Dock --- */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 40px;
            background-color: var(--taskbar-bg);
            backdrop-filter: blur(5px);
            display: flex;
            align-items: center;
            padding: 0 10px;
            z-index: 1000;
        }

        .launcher-button {
            background-color: #4a6273;
            border: none;
            padding: 8px 15px;
            margin-right: 10px;
            cursor: pointer;
            font-weight: bold;
            transition: background-color 0.2s, transform 0.1s;
            border-radius: 4px;
        }

        .launcher-button:hover {
            background-color: var(--accent-color);
            box-shadow: 0 0 8px rgba(66, 165, 245, 0.5);
        }

        /* --- Window Styling (General) --- */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background-color: var(--window-bg);
            border: 1px solid var(--border-color);
            box-shadow: 0 8px 16px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            z-index: 900; /* Below taskbar */
        }

        /* Window Header/Title Bar */
        .window-header {
            height: 30px;
            background-color: #1e2b33;
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 0 8px;
            cursor: grab; /* Indicates draggable */
        }

        .window-title {
            font-size: 14px;
            color: var(--text-color);
            flex-grow: 1;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .win-close {
            background: none;
            border: none;
            color: #aaa;
            font-size: 18px;
            cursor: pointer;
            padding: 0 5px;
            transition: color 0.2s;
        }

        .win-close:hover {
            color: var(--accent-color);
        }

        /* Window Content Area */
        .window-content {
            flex-grow: 1;
            padding: 10px;
            overflow: auto;
            background-color: #3a4d5c; /* Slightly different background for content */
        }

        /* --- Files App Specifics --- */
        #files-window .window-content {
            display: flex;
            flex-direction: column;
        }

        .file-toolbar {
            padding: 10px 0;
            border-bottom: 1px solid var(--border-color);
            margin-bottom: 10px;
            display: flex;
            align-items: center;
        }

        #files-path {
            font-size: 14px;
            padding: 5px 10px;
            background-color: #2b3e46;
            border-radius: 4px;
            margin-right: 20px;
        }

        #files-up {
            background-color: var(--accent-color);
            color: white;
            padding: 5px 10px;
            border: none;
            cursor: pointer;
            border-radius: 4px;
            transition: background-color 0.2s;
        }

        #files-up:hover {
            background-color: #398bfd;
        }

        /* File Listing */
        #file-listing {
            display: flex;
            flex-direction: column;
            gap: 5px;
        }

        .fs-item {
            padding: 8px 10px;
            cursor: pointer;
            border-radius: 4px;
            transition: background-color 0.2s, color 0.2s;
            display: flex;
            align-items: center;
        }

        .fs-item:hover {
            background-color: #4a6273;
        }

        .fs-item[data-type="folder"] {
            font-weight: bold;
            cursor: pointer;
        }

        /* Folder Icon Styling */
        .icon::before {
            content: "📁";
            margin-right: 10px;
        }
        .file-item .icon::before {
            content: "📄";
            margin-right: 10px;
        }

        /* --- Notepad App Specifics --- */
        #notepad-window .window-content {
            display: flex;
            flex-direction: column;
            padding: 0; /* Remove padding to make textarea fill space */
        }

        .tab-strip {
            display: flex;
            background-color: #2b3e46;
            border-bottom: 1px solid var(--border-color);
            height: 30px;
            padding-left: 5px;
        }

        .tab {
            cursor: pointer;
            padding: 8px 15px;
            background-color: #2b3e46;
            border: none;
            border-right: 1px solid var(--border-color);
            color: var(--text-color);
            font-size: 14px;
            transition: background-color 0.2s;
        }

        .tab.active {
            background-color: #3a4d5c; /* Matches window content bg */
            border-bottom: 1px solid var(--window-bg);
            z-index: 1;
        }

        #new-tab {
            background-color: var(--accent-color);
            color: white;
            border: none;
            padding: 8px 15px;
            cursor: pointer;
            margin-left: 5px;
            border-radius: 0 4px 4px 0;
        }

        #new-tab:hover {
            background-color: #398bfd;
        }

        #editor {
            width: 100%;
            height: calc(100% - 20px); /* Account for tab strip height */
            min-height: 240px;
            padding: 15px;
            border: none;
            resize: none;
            background-color: #3a4d5c;
            outline: none;
            font-family: monospace;
        }

    </style>
</head>
<body>

    <!-- DESKTOP ROOT -->
    <div id="desktop">

        <!-- 1. FILES WINDOW (Hidden by default) -->
        <div id="files-window" class="window" style="left: 50px; top: 30px; width: 600px;">
            <div class="window-header" id="files-header">
                <span class="window-title">File Explorer</span>
                <button class="win-close" data-target="files-window">&times;</button>
            </div>
            <div class="window-content">
                <!-- File Toolbar -->
                <div class="file-toolbar">
                    <button id="files-up">⬆️ Up</button>
                    <span id="files-path">/</span>
                </div>

                <!-- File Listing Area -->
                <div id="file-listing">
                    <!-- Content populated by JS -->
                </div>
            </div>
        </div>

        <!-- 2. NOTEPAD WINDOW (Hidden by default) -->
        <div id="notepad-window" class="window" style="left: 50px; top: 30px; width: 700px;">
            <div class="window-header" id="notepad-header">
                <span class="window-title">Notepad</span>
                <button class="win-close" data-target="notepad-window">&times;</button>
            </div>
            <div class="window-content">
                <!-- Tab Strip -->
                <div class="tab-strip">
                    <button id="new-tab" class="tab">+ New Tab</button>
                    <div id="tabs">
                        <!-- Tabs populated by JS -->
                    </div>
                </div>

                <!-- Editor Area -->
                <textarea id="editor"></textarea>
            </div>
        </div>

    </div>

    <!-- TASKBAR/DOCK -->
    <div id="taskbar">
        <button class="launcher-button" id="open-files">📂 Files</button>
        <button class="launcher-button" id="open-notepad">📝 Notepad</button>
    </div>


<script>
// ======================================================
// CORE DESKTOP LOGIC & UTILITIES
// ======================================================

const desktop = document.getElementById('desktop');
const taskbar = document.getElementById('taskbar');

/**
 * Handles window visibility and basic setup.
 * @param {string} targetId - The ID of the window element.
 */
function showWindow(targetId) {
    const windowEl = document.getElementById(targetId);
    if (windowEl) {
        // Ensure it's visible and positioned correctly
        windowEl.style.display = 'flex';
    }
}

/**
 * Hides a specific window by setting display none.
 * @param {string} targetId - The ID of the window element to hide.
 */
function hideWindow(targetId) {
    const windowEl = document.getElementById(targetId);
    if (windowEl) {
        windowEl.style.display = 'none';
    }
}

// --- Window Management Listeners ---

document.querySelectorAll('.win-close').forEach(button => {
    button.addEventListener('click', function() {
        const targetId = this.getAttribute('data-target');
        hideWindow(targetId);
    });
});

// Taskbar Launchers
document.getElementById('open-files').addEventListener('click', () => showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click', () => showWindow('notepad-window'));


// ======================================================
// 1. FILES APP LOGIC
// ======================================================

const fileListing = document.getElementById('file-listing');
const filesPathDisplay = document.getElementById('files-path');
const filesUpButton = document.getElementById('files-up');

// Fake Filesystem Data Structure: { path: { children: [name, type] } }
let currentPath = []; // Array representing the current directory path (e.g., ['home', 'user'])
const filesystem = {
    '/': {
        children: [
            ['bin', 'folder'], 
            ['etc', 'folder'], 
            ['home', 'folder'], 
            ['usr', 'folder'], 
            ['var', 'folder']
        ]
    },
    '/' + 'home': {
        children: [
            ['user', 'folder']
        ]
    },
    '/home/user': {
        children: [
            ['Documents', 'folder'], 
            ['Downloads', 'folder'], 
            ['Pictures', 'folder'],
            ['readme.txt', 'file']
        ]
    },
    '/home/user/Documents': {
        children: [
            ['Project Alpha Report.pdf', 'file'],
            ['Notes', 'folder']
        }
    },
    '/home/user/Downloads': {
        children: [
            ['setup.zip', 'file']
        ]
    },
    '/home/user/Pictures': {
        children: [
            ['selfie.jpg', 'file'],
            ['wallpaper.png', 'file']
        ]
    },
    // Deeper structure for testing navigation
    '/home/user/Documents/Notes': {
        children: [
            ['meeting_summary.md', 'file']
        }
    }
};

/**
 * Renders the file listing based on the current directory data.
 */
function renderFiles() {
    const pathKey = currentPath.join('/');
    let currentDirData;

    if (pathKey === '') { // Root case
        currentDirData = filesystem['/'];
    } else if (pathKey === 'user') { // Special handling for root path display
         // We need to find the actual data object corresponding to /home/user
        const fullPath = ['/', ...currentPath].join('/');
        currentDirData = filesystem[fullPath] || filesystem['/'];

    } else {
        const fullPathKey = '/' + currentPath.join('/');
        currentDirData = filesystem[fullPathKey] || filesystem['/'];
    }


    fileListing.innerHTML = '';

    if (!currentDirData || !currentDirData.children) {
        fileListing.innerHTML = '<p style="padding: 20px;">This directory is empty.</p>';
        return;
    }

    // Sort folders first, then files
    const sortedChildren = currentDirData.children.sort((a, b) => {
        const typeA = a[1];
        const typeB = b[1];
        if (typeA === 'folder' && typeB !== 'folder') return -1;
        if (typeA !== 'folder' && typeB === 'folder') return 1;
        return 0;
    });

    sortedChildren.forEach(([name, type]) => {
        const item = document.createElement('div');
        item.className = `fs-item ${type}-item`;
        item.setAttribute('data-name', name);
        itemsetAttribute('data-type', type);

        let iconClass = '';
        if (type === 'folder') {
            iconClass = 'icon';
        } else {
            iconClass = 'file-item';
        }

        item.innerHTML = `<span class="${iconClass}"></span>${name}`;
        fileListing.appendChild(item);
    });

    updatePathDisplay();
}

/**
 * Updates the path displayed in the toolbar.
 */
function updatePathDisplay() {
    let path = '/';
    if (currentPath.length > 0) {
        path += currentPath.join('/');
    }
    filesPathDisplay.textContent = path;
}

/**
 * Handles navigation into a folder when an item is double-clicked.
 * @param {string} name - The name of the folder/file.
 * @param {string} type - 'folder' or 'file'.
 */
function navigate(name, type) {
    if (type !== 'folder') return;

    // 1. Update path state
    currentPath.push(name);

    // 2. Re-render the view
    renderFiles();
}

/**
 * Navigates up one directory level.
 */
function goUp() {
    if (currentPath.length === 0) return; // Already at root

    currentPath.pop();
    renderFiles();
}


// --- File App Event Listeners ---

// Double-click handler for folder navigation
fileListing.addEventListener('dblclick', (e) => {
    const item = e.target.closest('.fs-item');
    if (!item) return;

    const name = item.getAttribute('data-name');
    const type = item.getAttribute('data-type');

    if (type === 'folder') {
        navigate(name, type);
    } else if (type === 'file') {
        alert(`[File Opened]: ${name}. This is a static view.`);
    }
});

// Up button handler
filesUpButton.addEventListener('click', goUp);


// ======================================================
// 2. NOTEPAD APP LOGIC (Tabs & Persistence)
// ======================================================

const tabsContainer = document.getElementById('tabs');
const editorArea = document.getElementById('editor');
const newTabButton = document.getElementById('new-tab');

let activeTabId = null; // Tracks the ID of the currently active tab

/**
 * Saves all current tab content to localStorage.
 */
function saveTabsToStorage() {
    const tabsData = [];
    document.querySelectorAll('.tab').forEach(tabEl => {
        const id = tabEl.dataset.id;
        const content = document.getElementById(`content-${id}`);
        if (content) {
            tabsData.push({
                id: id,
                title: tabEl.textContent.trim(),
                content: content.value
            });
        }
    });
    localStorage.setItem('notepadTabs', JSON.stringify(tabsData));
}

/**
 * Loads tabs and content from localStorage.
 */
function loadTabsFromStorage() {
    const stored = localStorage.getItem('notepadTabs');
    if (!stored) return [];

    return JSON.parse(stored);
}


/**
 * Switches the active tab, updating UI and focus.
 * @param {string} tabId - The ID of the tab to activate.
 */
function switchTab(tabId) {
    document.querySelectorAll('.tab').forEach(tab => {
        tab.classList.remove('active');
    });

    const activeTab = document.querySelector(`.tab[data-id="${tabId}"]`);
    if (activeTab) {
        activeTab.classList.add('active');
    }

    // Update editor content and focus
    document.querySelectorAll('#content-').forEach(textarea => textarea.disabled = true);
    const activeContentArea = document.getElementById(`content-${tabId}`);
    if (activeContentArea) {
        activeContentArea.disabled = false;
        activeContentArea.focus();
    }

    activeTabId = tabId;
}

/**
 * Creates a new tab element and associated content area.
 * @param {string} title - The initial title of the tab.
 * @param {string} content = '' - The initial text content.
 * @returns {HTMLElement} The ID of the newly created tab.
 */
function createTab(title, content = '') {
    const newId = Date.now().toString();

    // 1. Create Tab Button
    const tabButton = document.createElement('button');
    tabButton.className = 'tab';
    tabButton.textContent = title;
    tabButton.dataset.id = newId;
    tabButton.addEventListener('click', () => switchTab(newId));
    tabsContainer.appendChild(tabButton);

    // 2. Create Content Area (Textarea)
    const contentArea = document.createElement('textarea');
    contentArea.id = `content-${newId}`;
    contentArea.value = content;
    contentArea.style.display = 'none'; // Initially hidden/disabled until active
    document.querySelector('.window-content').appendChild(contentArea);

    // 3. Initialize state
    if (activeTabId === null) {
        switchTab(newId); // Activate the first tab created
    } else {
        // If tabs already exist, append and don't auto-activate
        tabButton.style.display = 'inline';
    }

    return newId;
}


/**
 * Initializes or restores the notepad application state.
 */
function initNotepad() {
    const storedTabs = loadTabsFromStorage();
    if (storedTabs.length === 0) {
        // Initial setup if nothing is saved
        createTab("Welcome Note", "Start typing your notes here...");
        saveTabsToStorage(); // Save initial state
    } else {
        // Restore existing tabs
        let firstTabId = null;
        storedTabs.forEach(tabData => {
            const tabButton = document.createElement('button');
            tabButton.className = 'tab';
            tabButton.textContent = tabData.title;
            tabButton.dataset.id = tabData.id;
            tabButton.addEventListener('click', () => switchTab(tabData.id));
            tabsContainer.appendChild(tabButton);

            const contentArea = document.createElement('textarea');
            contentArea.id = `content-${tabData.id}`;
            contentArea.value = tabData.content;
            document.querySelector('.window-content').appendChild(contentArea);

            if (firstTabId === null) {
                firstTabId = tabData.id;
            }
        });
        // Activate the first restored tab
        switchTab(firstTabId);
    }

    // Event listener for content changes (autosave on input)
    document.getElementById('editor').addEventListener('input', saveTabsToStorage);
    document.querySelectorAll('#content-textarea').forEach(area => {
        area.addEventListener('input', saveTabsToStorage);
    });


    // New Tab Button Listener
    newTabButton.addEventListener('click', () => {
        const newTitle = `Untitled ${tabsContainer.children.length + 1}`;
        createTab(newTitle, "");
        saveTabsToStorage();
    });

    // Global save listener (e.g., when window is closed/unloaded)
    window.addEventListener('beforeunload', saveTabsToStorage);
}


// ======================================================
// INITIALIZATION CALLS
// ======================================================

document.addEventListener('DOMContentLoaded', () => {
    // 1. Initialize Files App (Render root directory)
    renderFiles();

    // 2. Initialize Notepad App (Load/Create tabs and set up listeners)
    initNotepad();
});

</script>
</body>
</html>
